export interface WebTool {
  id: string;
  name: string;
  url: string;
  icon: string;
  openMode?: 'iframe' | 'window';
}

export enum ToolView {
  DASHBOARD = 'DASHBOARD',
  TIMESTAMP = 'TIMESTAMP',
  BASE_CONVERTER = 'BASE_CONVERTER',
  WEB_TOOLS = 'WEB_TOOLS',
  CALCULATOR = 'CALCULATOR',
  TRANSLATOR = 'TRANSLATOR',
  SETTINGS = 'SETTINGS'
}

import React, { useState } from 'react';
import { ToolView } from '../types';

interface SidebarProps {
  activeView: ToolView;
  setActiveView: (view: ToolView) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ activeView, setActiveView }) => {
  const [isCollapsed, setIsCollapsed] = useState(false);

  const items = [
    { view: ToolView.DASHBOARD, label: 'Dashboard', icon: '🏠' },
    { view: ToolView.TRANSLATOR, label: 'Translator', icon: '🌍' },
    { view: ToolView.CALCULATOR, label: 'Calculator', icon: '🧮' },
    { view: ToolView.TIMESTAMP, label: 'Timestamp', icon: '🕒' },
    { view: ToolView.BASE_CONVERTER, label: 'Base Conv', icon: '🔢' },
    { view: ToolView.WEB_TOOLS, label: 'Web Tools', icon: '🌐' },
    { view: ToolView.SETTINGS, label: 'Settings', icon: '⚙️' },
  ];

  return (
    <aside className={`${isCollapsed ? 'w-16' : 'w-64'} transition-all duration-300 bg-black/40 border-r border-white/10 flex flex-col p-4 relative group`}>
      <button 
        onClick={() => setIsCollapsed(!isCollapsed)}
        className="absolute -right-3 top-10 bg-white/10 border border-white/20 rounded-full w-6 h-6 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity z-10 hover:bg-white/20"
      >
        {isCollapsed ? '›' : '‹'}
      </button>

      <div className={`flex items-center ${isCollapsed ? 'justify-center' : 'space-x-2'} px-2 mb-8 overflow-hidden`}>
        <div className="flex space-x-1.5 flex-shrink-0">
          <div className="w-3 h-3 rounded-full bg-red-500" />
          {!isCollapsed && <div className="w-3 h-3 rounded-full bg-yellow-500" />}
          {!isCollapsed && <div className="w-3 h-3 rounded-full bg-green-500" />}
        </div>
        {!isCollapsed && <span className="text-white/60 font-bold ml-4 tracking-tight truncate">MacTools Pro</span>}
      </div>

      <nav className="flex-1 space-y-1 overflow-hidden">
        {items.map((item) => (
          <button
            key={item.view}
            onClick={() => setActiveView(item.view)}
            title={isCollapsed ? item.label : ''}
            className={`w-full flex items-center ${isCollapsed ? 'justify-center' : 'space-x-3 px-3'} py-2 rounded-lg transition-all ${
              activeView === item.view 
                ? 'bg-white/15 text-white shadow-lg' 
                : 'text-white/60 hover:bg-white/5 hover:text-white/80'
            }`}
          >
            <span className="text-xl flex-shrink-0">{item.icon}</span>
            {!isCollapsed && <span className="font-medium truncate">{item.label}</span>}
          </button>
        ))}
      </nav>

      {!isCollapsed && (
        <div className="mt-auto pt-4 border-t border-white/10">
          <div className="px-3 py-2 text-[10px] text-white/30 uppercase tracking-widest font-bold">
            System
          </div>
          <div className="px-3 py-1 text-white/50 text-[10px]">
            v1.2.0 Stable
          </div>
        </div>
      )}
    </aside>
  );
};

export default Sidebar;

import React, { useState, useEffect, useRef } from 'react';
import { ToolView } from '../types';

interface CommandPaletteProps {
  isOpen: boolean;
  onClose: () => void;
  onSelect: (view: ToolView) => void;
}

const CommandPalette: React.FC<CommandPaletteProps> = ({ isOpen, onClose, onSelect }) => {
  const [query, setQuery] = useState('');
  const inputRef = useRef<HTMLInputElement>(null);

  const commands = [
    { id: ToolView.DASHBOARD, name: 'Home / Dashboard', icon: '🏠', shortcut: 'H' },
    { id: ToolView.TRANSLATOR, name: 'Smart Translator', icon: '🌍', shortcut: 'F' },
    { id: ToolView.CALCULATOR, name: 'Calculator', icon: '🧮', shortcut: 'C' },
    { id: ToolView.TIMESTAMP, name: 'Timestamp Converter', icon: '🕒', shortcut: 'T' },
    { id: ToolView.BASE_CONVERTER, name: 'Base Converter (Hex/Bin)', icon: '🔢', shortcut: 'B' },
    { id: ToolView.WEB_TOOLS, name: 'Manage Web Tools', icon: '🌐', shortcut: 'W' },
  ];

  const filteredCommands = commands.filter(c => 
    c.name.toLowerCase().includes(query.toLowerCase()) || 
    c.id.toLowerCase().includes(query.toLowerCase())
  );

  useEffect(() => {
    if (isOpen) {
      setTimeout(() => inputRef.current?.focus(), 50);
    } else {
      setQuery('');
    }
  }, [isOpen]);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-start justify-center pt-[15vh] px-4 bg-black/20 backdrop-blur-sm" onClick={onClose}>
      <div 
        className="w-full max-w-xl bg-slate-900/90 border border-white/20 rounded-2xl shadow-2xl overflow-hidden flex flex-col"
        onClick={(e) => e.stopPropagation()}
      >
        <div className="p-4 border-b border-white/10 flex items-center space-x-3 bg-black/20">
          <span className="text-2xl">🔍</span>
          <input
            ref={inputRef}
            type="text"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder="Type a command or search..."
            className="flex-1 bg-transparent border-none outline-none text-white text-lg placeholder-white/30"
          />
          <div className="px-2 py-1 rounded bg-white/5 border border-white/10 text-[10px] text-white/40 font-mono">
            ESC to close
          </div>
        </div>

        <div className="max-h-[60vh] overflow-auto p-2">
          {filteredCommands.length > 0 ? (
            filteredCommands.map((cmd) => (
              <button
                key={cmd.id}
                onClick={() => onSelect(cmd.id)}
                className="w-full flex items-center justify-between p-3 rounded-xl hover:bg-white/10 transition-colors text-left group"
              >
                <div className="flex items-center space-x-3">
                  <span className="text-xl group-hover:scale-110 transition-transform">{cmd.icon}</span>
                  <span className="text-white/80 font-medium">{cmd.name}</span>
                </div>
                <div className="text-xs text-white/20 font-mono px-2 py-1 rounded border border-white/5 group-hover:border-white/20">
                  {cmd.shortcut}
                </div>
              </button>
            ))
          ) : (
            <div className="p-12 text-center text-white/30 italic">
              No commands matching "{query}"
            </div>
          )}
        </div>

        <div className="p-3 bg-black/40 border-t border-white/10 flex items-center justify-between">
           <div className="flex space-x-4">
              <span className="text-[10px] text-white/30 flex items-center">
                <kbd className="bg-white/10 px-1 rounded mr-1">↑↓</kbd> to navigate
              </span>
              <span className="text-[10px] text-white/30 flex items-center">
                <kbd className="bg-white/10 px-1 rounded mr-1">↵</kbd> to select
              </span>
           </div>
           <span className="text-[10px] text-white/20">MacTools Assistant</span>
        </div>
      </div>
    </div>
  );
};

export default CommandPalette;

import React, { useState, useEffect, useCallback } from 'react';
import { GoogleGenAI } from "@google/genai";

const languages = [
  { code: 'auto', name: 'Auto Detect' },
  { code: 'en', name: 'English' },
  { code: 'zh', name: 'Chinese (Simplified)' },
  { code: 'ja', name: 'Japanese' },
  { code: 'ko', name: 'Korean' },
  { code: 'fr', name: 'French' },
  { code: 'de', name: 'German' },
  { code: 'es', name: 'Spanish' },
];

const Translator: React.FC = () => {
  const [sourceText, setSourceText] = useState('');
  const [targetText, setTargetText] = useState('');
  const [sourceLang, setSourceLang] = useState('auto');
  const [targetLang, setTargetLang] = useState('zh');
  const [isLoading, setIsLoading] = useState(false);
  const [history, setHistory] = useState<{source: string, target: string}[]>(() => {
    const saved = localStorage.getItem('mac_translate_history');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('mac_translate_history', JSON.stringify(history));
  }, [history]);

  const handleTranslate = useCallback(async () => {
    if (!sourceText.trim()) {
      setTargetText('');
      return;
    }

    setIsLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Translate the following text to ${languages.find(l => l.code === targetLang)?.name}. 
      Source language hint: ${sourceLang === 'auto' ? 'detect automatically' : sourceLang}.
      Provide only the translated text.
      Text: "${sourceText}"`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });

      const translated = response.text?.trim() || '';
      setTargetText(translated);

      if (translated) {
        setHistory(prev => [{ source: sourceText, target: translated }, ...prev].slice(0, 10));
      }
    } catch (error) {
      console.error('Translation error:', error);
      setTargetText('Error occurred during translation. Please try again.');
    } finally {
      setIsLoading(false);
    }
  }, [sourceText, sourceLang, targetLang]);

  // Debounced effect for automatic translation
  useEffect(() => {
    const timer = setTimeout(() => {
      if (sourceText.length > 0) handleTranslate();
    }, 1000);
    return () => clearTimeout(timer);
  }, [sourceText, sourceLang, targetLang]);

  const swapLanguages = () => {
    if (sourceLang === 'auto') return;
    setSourceLang(targetLang);
    setTargetLang(sourceLang);
    setSourceText(targetText);
    setTargetText(sourceText);
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
  };

  return (
    <div className="p-8 max-w-5xl mx-auto text-white h-full flex flex-col">
      <div className="flex items-center justify-between mb-8">
        <div>
          <h2 className="text-2xl font-bold flex items-center">
            <span className="mr-2">🌍</span> Smart Translator
          </h2>
          <p className="text-sm text-white/40 mt-1">AI-powered context-aware translations.</p>
        </div>
        <div className="flex bg-white/5 rounded-xl p-1 border border-white/10">
          <button 
            onClick={() => setSourceText('')}
            className="px-4 py-1.5 text-xs font-bold text-white/40 hover:text-white transition-colors"
          >
            Clear
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
        {/* Source Section */}
        <div className="flex flex-col space-y-3">
          <div className="flex items-center justify-between">
            <select 
              value={sourceLang}
              onChange={(e) => setSourceLang(e.target.value)}
              className="bg-white/10 border border-white/10 rounded-lg px-3 py-1.5 text-sm focus:outline-none focus:ring-1 focus:ring-indigo-500"
            >
              {languages.map(lang => (
                <option key={lang.code} value={lang.code}>{lang.name}</option>
              ))}
            </select>
          </div>
          <div className="relative flex-1">
            <textarea
              value={sourceText}
              onChange={(e) => setSourceText(e.target.value)}
              placeholder="Type something to translate..."
              className="w-full h-48 bg-black/30 border border-white/10 rounded-2xl p-4 text-lg focus:outline-none focus:border-indigo-500 transition-all resize-none font-sans"
            />
          </div>
        </div>

        {/* Swap Button (Middle for desktop, but logically here) */}
        <div className="hidden lg:flex items-center justify-center -mx-3 z-10">
          <button 
            onClick={swapLanguages}
            disabled={sourceLang === 'auto'}
            className="w-10 h-10 bg-indigo-600 hover:bg-indigo-500 disabled:bg-white/10 rounded-full flex items-center justify-center shadow-xl transition-all active:scale-90"
          >
            ⇄
          </button>
        </div>

        {/* Target Section */}
        <div className="flex flex-col space-y-3">
          <div className="flex items-center justify-between">
            <select 
              value={targetLang}
              onChange={(e) => setTargetLang(e.target.value)}
              className="bg-white/10 border border-white/10 rounded-lg px-3 py-1.5 text-sm focus:outline-none focus:ring-1 focus:ring-indigo-500"
            >
              {languages.filter(l => l.code !== 'auto').map(lang => (
                <option key={lang.code} value={lang.code}>{lang.name}</option>
              ))}
            </select>
            <button 
              onClick={() => copyToClipboard(targetText)}
              className="p-1.5 hover:bg-white/10 rounded-lg transition-colors text-white/40 hover:text-white"
              title="Copy result"
            >
              📋
            </button>
          </div>
          <div className="relative flex-1">
            <div className={`w-full h-48 bg-white/5 border border-white/10 rounded-2xl p-4 text-lg overflow-auto ${isLoading ? 'opacity-50' : ''}`}>
              {isLoading ? (
                <div className="flex items-center space-x-2 text-white/30 italic">
                  <div className="w-4 h-4 border-2 border-indigo-500 border-t-transparent rounded-full animate-spin" />
                  <span>Translating...</span>
                </div>
              ) : (
                targetText || <span className="text-white/20 italic">Translation will appear here</span>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* History Section */}
      <div className="mt-auto">
        <h4 className="text-[10px] font-bold text-white/30 uppercase tracking-widest mb-4">Recent Translations</h4>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-3 max-h-40 overflow-auto pr-2">
          {history.length > 0 ? history.map((item, i) => (
            <div 
              key={i} 
              onClick={() => { setSourceText(item.source); setTargetText(item.target); }}
              className="bg-white/5 hover:bg-white/10 border border-white/5 p-3 rounded-xl cursor-pointer transition-colors group"
            >
              <div className="text-xs text-white/60 truncate mb-1">{item.source}</div>
              <div className="text-xs text-indigo-400 font-medium truncate group-hover:text-indigo-300 transition-colors">{item.target}</div>
            </div>
          )) : (
            <div className="text-xs text-white/20 italic">Your translation history will appear here.</div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Translator;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import Sidebar from './components/Sidebar';
import TimestampConverter from './components/TimestampConverter';
import BaseConverter from './components/BaseConverter';
import WebToolManager from './components/WebToolManager';
import Calculator from './components/Calculator';
import Translator from './components/Translator';
import CommandPalette from './components/CommandPalette';
import Settings from './components/Settings';
import { ToolView, WebTool } from './types';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ToolView>(ToolView.DASHBOARD);
  const [isCommandPaletteOpen, setIsCommandPaletteOpen] = useState(false);
  const [selectedWebTool, setSelectedWebTool] = useState<WebTool | null>(null);
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);
  const [isInstalled, setIsInstalled] = useState(false);
  const [iframeLoading, setIframeLoading] = useState(true);
  const iframeRef = useRef<HTMLIFrameElement>(null);

  const [webTools, setWebTools] = useState<WebTool[]>(() => {
    const saved = localStorage.getItem('mac_web_tools');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Google (Search Only)', url: 'https://www.google.com/search?igu=1', icon: '🔍', openMode: 'iframe' },
      { id: '2', name: 'GitHub', url: 'https://github.com', icon: '🐙', openMode: 'iframe' }
    ];
  });

  useEffect(() => {
    localStorage.setItem('mac_web_tools', JSON.stringify(webTools));
  }, [webTools]);

  // PWA Install Logic
  useEffect(() => {
    const handleBeforeInstallPrompt = (e: Event) => {
      e.preventDefault();
      setDeferredPrompt(e);
    };

    const handleAppInstalled = () => {
      setIsInstalled(true);
      setDeferredPrompt(null);
    };

    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    window.addEventListener('appinstalled', handleAppInstalled);

    if (window.matchMedia('(display-mode: standalone)').matches) {
      setIsInstalled(true);
    }

    return () => {
      window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
      window.removeEventListener('appinstalled', handleAppInstalled);
    };
  }, []);

  const installPWA = async () => {
    if (!deferredPrompt) return;
    deferredPrompt.prompt();
    const { outcome } = await deferredPrompt.userChoice;
    if (outcome === 'accepted') {
      setDeferredPrompt(null);
    }
  };

  const toggleCommandPalette = useCallback(() => {
    setIsCommandPaletteOpen(prev => !prev);
  }, []);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        toggleCommandPalette();
      }
      if (e.key === 'Escape') {
        setIsCommandPaletteOpen(false);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [toggleCommandPalette]);

  const refreshIframe = () => {
    if (iframeRef.current) {
      setIframeLoading(true);
      const currentSrc = iframeRef.current.src;
      iframeRef.current.src = '';
      setTimeout(() => {
        if (iframeRef.current) iframeRef.current.src = currentSrc;
      }, 10);
    }
  };

  const openExternally = () => {
    if (selectedWebTool) {
      window.open(selectedWebTool.url, '_blank');
    }
  };

  const handleToolSelect = (tool: WebTool) => {
    if (tool.openMode === 'window') {
      window.open(tool.url, '_blank');
    } else {
      setSelectedWebTool(tool);
      setIframeLoading(true);
      setActiveView(ToolView.WEB_TOOLS);
    }
  };

  const renderView = () => {
    switch (activeView) {
      case ToolView.TIMESTAMP: return <TimestampConverter />;
      case ToolView.BASE_CONVERTER: return <BaseConverter />;
      case ToolView.CALCULATOR: return <Calculator />;
      case ToolView.TRANSLATOR: return <Translator />;
      case ToolView.SETTINGS: 
        return <Settings 
          onInstall={installPWA} 
          isInstallable={!!deferredPrompt} 
          isInstalled={isInstalled} 
        />;
      case ToolView.WEB_TOOLS:
        return (
          <WebToolManager 
            webTools={webTools} 
            setWebTools={setWebTools} 
            onSelectTool={handleToolSelect}
          />
        );
      case ToolView.DASHBOARD:
      default:
        return (
          <div className="flex flex-col items-center justify-center h-full text-white/80 p-12 overflow-y-auto">
            <h1 className="text-4xl font-bold mb-4">Welcome to MacTools</h1>
            <p className="text-lg opacity-60 mb-8">Press <kbd className="bg-white/10 px-2 py-1 rounded">⌘K</kbd> to open command palette</p>

            {deferredPrompt && !isInstalled && (
              <button 
                onClick={installPWA}
                className="mb-10 px-6 py-3 bg-indigo-600 hover:bg-indigo-500 rounded-full font-bold shadow-xl shadow-indigo-900/40 transition-all flex items-center space-x-2 animate-bounce"
              >
                <span>📥</span>
                <span>Install to Desktop</span>
              </button>
            )}

            <div className="grid grid-cols-2 gap-4 w-full max-w-2xl">
              {[
                { view: ToolView.TRANSLATOR, icon: '🌍', label: 'Translator', sub: 'AI Smart Translate' },
                { view: ToolView.CALCULATOR, icon: '🧮', label: 'Calculator', sub: 'Math & History' },
                { view: ToolView.TIMESTAMP, icon: '🕒', label: 'Timestamp', sub: 'Unix converter' },
                { view: ToolView.BASE_CONVERTER, icon: '🔢', label: 'Base Converter', sub: 'Hex/Bin/Oct' },
                { view: ToolView.WEB_TOOLS, icon: '🌐', label: 'Web Tools', sub: 'Embedded apps' }
              ].map(card => (
                <button 
                  key={card.view}
                  onClick={() => setActiveView(card.view)}
                  className="p-6 bg-white/5 hover:bg-white/10 border border-white/10 rounded-2xl transition-all text-left group"
                >
                  <div className="text-2xl mb-2 group-hover:scale-110 transition-transform">{card.icon}</div>
                  <div className="font-semibold">{card.label}</div>
                  <div className="text-sm opacity-50">{card.sub}</div>
                </button>
              ))}
            </div>
          </div>
        );
    }
  };

  return (
    <div className="flex h-screen w-screen overflow-hidden bg-gradient-to-br from-slate-900 via-slate-800 to-indigo-950">
      <Sidebar activeView={activeView} setActiveView={setActiveView} />

      <main className="flex-1 overflow-auto relative mac-blur bg-black/20 flex flex-col">
        <div className="window-drag-handle shrink-0" />

        <div className="flex-1 overflow-auto">
          {activeView === ToolView.WEB_TOOLS && selectedWebTool ? (
            <div className="h-full w-full flex flex-col">
              <div className="h-12 bg-black/60 border-b border-white/10 flex items-center px-4 justify-between">
                <div className="flex items-center space-x-4 overflow-hidden">
                  <div className="flex items-center space-x-2">
                      <span className="text-lg">{selectedWebTool.icon}</span>
                      <span className="text-sm font-bold text-white/80 truncate">{selectedWebTool.name}</span>
                  </div>
                  <div className="flex items-center space-x-1 border-l border-white/10 pl-4">
                      <button onClick={refreshIframe} className="p-1.5 hover:bg-white/10 rounded-lg text-white/40 hover:text-white transition-colors" title="Refresh">🔄</button>
                      <button onClick={openExternally} className="p-1.5 hover:bg-white/10 rounded-lg text-white/40 hover:text-white transition-colors flex items-center space-x-1" title="Open in browser">
                        <span className="text-xs font-medium">Open Externally</span>
                        <span>↗️</span>
                      </button>
                  </div>
                </div>
                <div className="flex items-center space-x-3">
                    <div className="hidden md:flex flex-col items-end mr-2">
                      <span className="text-[9px] text-white/30 uppercase font-bold leading-none">Status</span>
                      <span className={`text-[10px] ${iframeLoading ? 'text-yellow-500' : 'text-green-500'} font-mono`}>
                        ● {iframeLoading ? 'LOADING' : 'READY'}
                      </span>
                    </div>
                    <button onClick={() => setSelectedWebTool(null)} className="px-3 py-1 bg-white/5 hover:bg-white/15 rounded-md text-white/60 text-xs transition-colors border border-white/10">Close</button>
                </div>
              </div>
              <div className="flex-1 relative bg-slate-900">
                {iframeLoading && (
                  <div className="absolute inset-0 z-10 flex flex-col items-center justify-center bg-slate-900 text-white/40 space-y-4">
                    <div className="w-10 h-10 border-4 border-blue-500/20 border-t-blue-500 rounded-full animate-spin"></div>
                    <div className="text-center">
                      <p className="text-sm font-medium">Loading Tool...</p>
                      <p className="text-[10px] mt-2 max-w-xs opacity-60">If this takes too long, the site might be blocking iframe access (X-Frame-Options).</p>
                    </div>
                  </div>
                )}
                <iframe 
                  ref={iframeRef} 
                  src={selectedWebTool.url} 
                  onLoad={() => setIframeLoading(false)}
                  className="absolute inset-0 w-full h-full border-none" 
                  sandbox="allow-same-origin allow-scripts allow-popups allow-forms allow-modals allow-downloads allow-popups-to-escape-sandbox" 
                />
              </div>
            </div>
          ) : (
            renderView()
          )}
        </div>
      </main>

      <CommandPalette 
        isOpen={isCommandPaletteOpen} 
        onClose={() => setIsCommandPaletteOpen(false)} 
        onSelect={(view) => {
          setActiveView(view);
